defmodule DevopsAutomation.CommandService do
  @moduledoc """
  Secure command execution service using an allowlist approach.
  Only pre-approved commands with validated arguments can be executed.
  """

  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "memory_info" => {"/usr/bin/free", ["-m"]},
    "uptime" => {"/usr/bin/uptime", []},
    "list_containers" => {"/usr/bin/docker", ["ps", "--format", "table {{.Names}}\t{{.Status}}"]},
    "service_status" => {"/usr/bin/systemctl", ["status"]},
    "ping" => {"/usr/bin/ping", ["-c", "4"]}
  }

  @doc """
  Executes a pre-approved command by name with optional validated arguments.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, args \\ []) when is_binary(command_name) and is_list(args) do
    case Map.get(@allowed_commands, command_name) do
      nil ->
        {:error, :command_not_allowed}

      {executable, base_args} ->
        validated_args = validate_args(command_name, args)

        case validated_args do
          {:ok, safe_args} ->
            full_args = base_args ++ safe_args

            try do
              {output, exit_code} =
                System.cmd(executable, full_args,
                  stderr_to_stdout: true,
                  env: [{"PATH", "/usr/bin:/bin"}],
                  parallelism: true
                )

              if exit_code == 0 do
                {:ok, %{output: output, exit_code: exit_code}}
              else
                {:error, %{output: output, exit_code: exit_code}}
              end
            rescue
              e in ErlangError ->
                {:error, %{reason: :execution_failed, detail: Exception.message(e)}}
            end

          {:error, reason} ->
            {:error, reason}
        end
    end
  end

  def list_available_commands do
    Map.keys(@allowed_commands)
  end

  # Validate arguments per command to prevent injection
  defp validate_args("service_status", [service_name]) do
    if Regex.match?(~r/\A[a-zA-Z0-9_\-\.]+\z/, service_name) do
      {:ok, [service_name]}
    else
      {:error, :invalid_argument}
    end
  end

  defp validate_args("ping", [host]) do
    if valid_hostname_or_ip?(host) do
      {:ok, [host]}
    else
      {:error, :invalid_argument}
    end
  end

  defp validate_args(_command, []), do: {:ok, []}
  defp validate_args(_command, _args), do: {:error, :arguments_not_supported}

  defp valid_hostname_or_ip?(host) do
    Regex.match?(~r/\A[a-zA-Z0-9][a-zA-Z0-9\-\.]{0,253}[a-zA-Z0-9]\z/, host) and
      not String.contains?(host, "..")
  end
end

